// // This module implements an 8-bit shift register that shifts right when the shift_left signal is high and shifts left when the shift_right signal is high.
module shift_register_8 
(
  input clk,
  input rst,
  input shift_left,
  input shift_right,
  input load,
  input [7:0] data_in,

  output reg [7:0] data_out
);

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      data_out <= 8'b00000000;
    end 

	else if (load) 
	begin
      data_out <= data_in;
    end 

	else if (shift_left) 
	begin
      data_out <= data_out << 1;
    end 

	else if (shift_right) 
	begin
      data_out <= data_out >> 1;
    end
  end

endmodule
